using System.Reflection;

var asm = Assembly.LoadFrom(Path.Combine(
    Environment.GetFolderPath(Environment.SpecialFolder.UserProfile),
    ".nuget/packages/microsoft.agents.ai/1.6.1/lib/net10.0/Microsoft.Agents.AI.dll"));

// Check AgentRunOptions and related
foreach (var t in asm.GetExportedTypes()
    .Where(t => t.Name.Contains("RunOptions") || t.Name == "AgentSession" || t.Name.Contains("MaximumIteration") || t.Name.Contains("ChatHistoryProvider"))
    .OrderBy(t => t.Name))
{
    Console.WriteLine($"\n=== {t.FullName} ===");
    foreach (var c in t.GetConstructors(BindingFlags.Public | BindingFlags.Instance))
        Console.WriteLine($"  ctor({string.Join(", ", c.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
    foreach (var p in t.GetProperties(BindingFlags.Public | BindingFlags.Instance))
        Console.WriteLine($"  prop {p.PropertyType.Name} {p.Name}");
    foreach (var m in t.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
        Console.WriteLine($"  {m.ReturnType.Name} {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
}

// Also check ChatOptions from MEAI for MaxOutputTokens etc
var meaiAsm = Assembly.LoadFrom(Path.Combine(
    Environment.GetFolderPath(Environment.SpecialFolder.UserProfile),
    ".nuget/packages/microsoft.extensions.ai.abstractions/9.6.0/lib/net10.0/Microsoft.Extensions.AI.Abstractions.dll"));
var chatOptionsType = meaiAsm.GetExportedTypes().FirstOrDefault(t => t.Name == "ChatOptions");
if (chatOptionsType != null)
{
    Console.WriteLine($"\n=== {chatOptionsType.FullName} ===");
    foreach (var p in chatOptionsType.GetProperties(BindingFlags.Public | BindingFlags.Instance))
        Console.WriteLine($"  prop {p.PropertyType.Name} {p.Name}");
}
EOF
