 using System.ComponentModel;
 using System.Net;
 using System.Text;
 using System.Text.RegularExpressions;
 using Microsoft.Extensions.AI;
 using Microsoft.Agents.AI;
 using OpenAI;

 // ── Configuration ──────────────────────────────────────────────────────────────
 var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
     ?? throw new InvalidOperationException(
         "Set the OPENAI_API_KEY environment variable before running.");

 var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

 // ── Build the chat client (MEAI abstraction over OpenAI) ───────────────────────
 var openAiClient = new OpenAIClient(apiKey);
 IChatClient chatClient = openAiClient.GetChatClient(modelId).AsIChatClient();

 // ── Create tools ───────────────────────────────────────────────────────────────
 var researchTools = new ResearchTools(new HttpClient());

 var tools = new AITool[]
 {
     AIFunctionFactory.Create(researchTools.SearchWebAsync),
     AIFunctionFactory.Create(researchTools.TakeNote),
     AIFunctionFactory.Create(researchTools.GetNotes),
 };

 // ── Create the agent ───────────────────────────────────────────────────────────
 var agent = new ChatClientAgent(
     chatClient,
     new ChatClientAgentOptions
     {
         Name = "ResearchAgent",
         Description = "An AI agent that researches topics by searching the web and taking notes.",
         ChatOptions = new ChatOptions
         {
             Temperature = 0f,
             MaxOutputTokens = 4096,
             Tools = [.. tools],
         },
     });

 var instructions = """
     You are a research assistant. When given a topic:
     1. Use SearchWebAsync to find relevant information (make 2-3 searches with different queries).
     2. Use TakeNote to record key findings from each search (title each note descriptively).
     3. Use GetNotes to review all notes you have collected.
     4. Produce a well-structured summary with sections, citing the sources you found.
     Be thorough but concise. Always search before summarizing.
     """;

 // ── Run the agent ──────────────────────────────────────────────────────────────
 Console.WriteLine("╔══════════════════════════════════════════╗");
 Console.WriteLine("║       🔍  AI Research Agent  🔍          ║");
 Console.WriteLine("╠══════════════════════════════════════════╣");
 Console.WriteLine("║  Enter a topic to research, or 'quit'.  ║");
 Console.WriteLine("╚══════════════════════════════════════════╝");
 Console.WriteLine();

 while (true)
 {
     Console.Write("Research topic> ");
     var topic = Console.ReadLine()?.Trim();
     if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
         break;

     researchTools.ClearNotes();

     Console.WriteLine($"\nResearching: {topic}\n");

     var session = await agent.CreateSessionAsync();

     var userMessage = $"{instructions}\n\nResearch the following topic and provide a comprehensive summary:\n{topic}";

     await foreach (var update in agent.RunStreamingAsync(userMessage, session))
     {
         if (update.Role == ChatRole.Assistant && !string.IsNullOrEmpty(update.Text))
         {
             Console.Write(update.Text);
         }
     }

     Console.WriteLine("\n");
 }

 Console.WriteLine("Goodbye!");

