     [Description("Save a research note. Use this to record key findings from searches.")]
     public string TakeNote(
         [Description("A short descriptive title for the note")] string title,
         [Description("The content/findings to record")] string content)
     {
         Console.WriteLine($"  📝 Note saved: \"{title}\"");
         _notes.Add(new Note(title, content, DateTime.UtcNow));
         return $"Note saved: \"{title}\" ({_notes.Count} total notes)";
     }

     [Description("Retrieve all research notes taken so far.")]
     public string GetNotes()
     {
         if (_notes.Count == 0)
             return "No notes have been taken yet.";

         var sb = new StringBuilder();
         for (var i = 0; i < _notes.Count; i++)
         {
             var note = _notes[i];
             sb.AppendLine($"--- Note {i + 1}: {note.Title} ---");
             sb.AppendLine(note.Content);
             sb.AppendLine();
         }

         return sb.ToString();
     }

     public void ClearNotes() => _notes.Clear();

     private static List<(string Title, string Url, string Snippet)> ParseSearchResults(string html)
     {
         var results = new List<(string, string, string)>();

         var linkMatches = ResultLinkRegex().Matches(html);
         var snippetMatches = SnippetRegex().Matches(html);

         for (var i = 0; i < linkMatches.Count && i < 8; i++)
         {
             var title = StripHtml(linkMatches[i].Groups[2].Value).Trim();
             var rawUrl = linkMatches[i].Groups[1].Value;

             // DuckDuckGo wraps URLs in a redirect; extract the real URL
             var urlMatch = ExtractUrlRegex().Match(rawUrl);
             var url = urlMatch.Success
                 ? Uri.UnescapeDataString(urlMatch.Groups[1].Value)
                 : rawUrl;

             var snippet = i < snippetMatches.Count
                 ? StripHtml(snippetMatches[i].Groups[1].Value).Trim()
                 : "";

             if (!string.IsNullOrWhiteSpace(title))
                 results.Add((title, url, snippet));
         }

         return results;
     }

     private static string StripHtml(string html)
     {
         var text = HtmlTagRegex().Replace(html, "");
         return WebUtility.HtmlDecode(text);
     }

     [GeneratedRegex("""<a[^>]+class="result__a"[^>]+href="([^"]*)"[^>]*>(.*?)</a>""", RegexOptions.Singleline)]
     private static partial Regex ResultLinkRegex();

     [GeneratedRegex("""<a[^>]+class="result__snippet"[^>]*>(.*?)</a>""", RegexOptions.Singleline)]
     private static partial Regex SnippetRegex();

     [GeneratedRegex("""uddg=([^&]+)""")]
     private static partial Regex ExtractUrlRegex();

     [GeneratedRegex("<[^>]+>")]
     private static partial Regex HtmlTagRegex();
 }

 record Note(string Title, string Content, DateTime Timestamp);
